// ---------------------------------------------------------------------------
// Discussions
// ---------------------------------------------------------------------------

import type { DiscussionItem, CreateDiscussionInput } from "./api.schemas";

export const getListDiscussionsUrl = (problemSlug: string) =>
  `/api/discussions/${encodeURIComponent(problemSlug)}`;

export const listDiscussions = async (
  problemSlug: string,
  options?: RequestInit,
): Promise<DiscussionItem[]> => {
  return customFetch<DiscussionItem[]>(getListDiscussionsUrl(problemSlug), {
    ...options,
    method: "GET",
  });
};

export const getListDiscussionsQueryKey = (problemSlug: string) =>
  [getListDiscussionsUrl(problemSlug)] as const;

export function getListDiscussionsQueryOptions(
  problemSlug: string,
  options?: {
    query?: UseQueryOptions<DiscussionItem[], ErrorType<unknown>, DiscussionItem[]>;
    request?: SecondParameter<typeof customFetch>;
  },
) {
  const { query: queryOptions, request: requestOptions } = options ?? {};
  const queryKey = queryOptions?.queryKey ?? getListDiscussionsQueryKey(problemSlug);
  return {
    queryKey,
    queryFn: () => listDiscussions(problemSlug, requestOptions),
    enabled: !!problemSlug,
    ...queryOptions,
  };
}

export function useListDiscussions<
  TData = DiscussionItem[],
  TError = ErrorType<unknown>,
>(
  problemSlug: string,
  options?: {
    query?: UseQueryOptions<DiscussionItem[], TError, TData>;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListDiscussionsQueryOptions(problemSlug, options);
  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };
  return { ...query, queryKey: queryOptions.queryKey };
}

export const createDiscussion = async (
  data: CreateDiscussionInput,
  options?: RequestInit,
): Promise<DiscussionItem> => {
  return customFetch<DiscussionItem>(`/api/discussions`, {
    ...options,
    method: "POST",
    body: JSON.stringify(data),
  });
};

export function useCreateDiscussion<TError = ErrorType<unknown>>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createDiscussion>>,
    TError,
    { data: CreateDiscussionInput },
    unknown
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof createDiscussion>>,
  TError,
  { data: CreateDiscussionInput },
  unknown
> {
  const { mutation: mutationOptions, request: requestOptions } = options ?? {};
  return useMutation({
    mutationFn: ({ data }: { data: CreateDiscussionInput }) =>
      createDiscussion(data, requestOptions),
    ...mutationOptions,
  });
}

export const deleteDiscussion = async (
  id: number,
  userId: string,
  options?: RequestInit,
): Promise<void> => {
  return customFetch<void>(
    `/api/discussions/${id}?userId=${encodeURIComponent(userId)}`,
    { ...options, method: "DELETE" },
  );
};

export function useDeleteDiscussion<TError = ErrorType<unknown>>(options?: {
  mutation?: UseMutationOptions<
    void,
    TError,
    { id: number; userId: string },
    unknown
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<void, TError, { id: number; userId: string }, unknown> {
  const { mutation: mutationOptions, request: requestOptions } = options ?? {};
  return useMutation({
    mutationFn: ({ id, userId }: { id: number; userId: string }) =>
      deleteDiscussion(id, userId, requestOptions),
    ...mutationOptions,
  });
}
